PYTHONPATH=fibonacci_exploration/src python - <<'PY'
from fibonacci_exploration.validation import (
    FIBONACCI_INPUT_RULES,
    RANGE_ERROR_MESSAGE,
    TYPE_ERROR_MESSAGE,
    normalize_fibonacci_index,
)

class Indexable:
    def __index__(self):
        return 7

assert normalize_fibonacci_index(0) == 0
assert normalize_fibonacci_index(11) == 11
assert normalize_fibonacci_index(Indexable()) == 7
assert FIBONACCI_INPUT_RULES['type_error_message'] == TYPE_ERROR_MESSAGE
assert FIBONACCI_INPUT_RULES['range_error_message'] == RANGE_ERROR_MESSAGE

for invalid in (True, 2.5, '8'):
    try:
        normalize_fibonacci_index(invalid)
    except TypeError as exc:
        assert str(exc) == TYPE_ERROR_MESSAGE
    else:
        raise AssertionError(f'expected TypeError for {invalid!r}')

try:
    normalize_fibonacci_index(-1)
except ValueError as exc:
    assert str(exc) == RANGE_ERROR_MESSAGE
else:
    raise AssertionError('expected ValueError for -1')

print('validation checks passed')
PY
